const { createClient } = require\('@supabase/supabase-js'\);
const c = createClient\('$NEXT_PUBLIC_SUPABASE_URL', '$SUPABASE_SERVICE_ROLE_KEY'\);
c.from\('dict_mos_to_civilian'\).select\('military_code, branch'\).order\('military_code'\).then\(r => {
  const codes = r.data.map\(d => d.military_code.toLowerCase\(\)\);
  const unique = new Set\(codes\);
  console.log\('Total rows:', r.data.length\);
  console.log\('Unique lowercase codes:', unique.size\);

  // Find duplicates
  const counts = {};
  codes.forEach\(c => { counts[c] = \(counts[c] || 0\) + 1; }\);
  const dupes = Object.entries\(counts\).filter\(\([,v]\) => v > 1\);
  console.log\('Duplicate codes:', dupes.length\);
  dupes.slice\(0, 10\).forEach\(\([k,v]\) => console.log\('  ', k, '=', v\)\);
}\);
